program BasicWorkaround;
{ Test workaround patterns for BASIC interpreter without arrays/procedures.
  Uses flat global variables and manual dispatch patterns. }
var
  { Simulate a small variable table (A=0..E=4) using globals }
  va, vb, vc, vd, ve: integer;
  { Simulate token buffer as a few globals }
  t0, t1, t2, t3, t4, t5, t6, t7: integer;
  { State }
  pos, tok, val, ch: integer;
  running: boolean;

begin
  { Test 1: Variable set/get by index using if-chain }
  { Set variable C (index 2) to 42 }
  pos := 2;
  val := 42;
  if pos = 0 then va := val;
  if pos = 1 then vb := val;
  if pos = 2 then vc := val;
  if pos = 3 then vd := val;
  if pos = 4 then ve := val;

  { Get variable C back }
  val := 0;
  if pos = 0 then val := va;
  if pos = 1 then val := vb;
  if pos = 2 then val := vc;
  if pos = 3 then val := vd;
  if pos = 4 then val := ve;

  if val = 42 then
    writeln('PASS 1')
  else
    writeln('FAIL 1');

  { Test 2: Token buffer fill and scan }
  t0 := 129;  { PRINT token }
  t1 := 192;  { string marker }
  t2 := 72;   { 'H' }
  t3 := 73;   { 'I' }
  t4 := 0;    { string end }
  t5 := 0;    { line end }

  { Read token at position 0 }
  pos := 0;
  tok := 0;
  if pos = 0 then tok := t0;
  if pos = 1 then tok := t1;
  if pos = 2 then tok := t2;

  if tok = 129 then
    writeln('PASS 2')
  else
    writeln('FAIL 2');

  { Test 3: Character classification (uppercase A-Z = 65-90) }
  ch := 72;  { 'H' }
  if (ch >= 65) and (ch <= 90) then
    writeln('PASS 3')
  else
    writeln('FAIL 3');

  { Test 4: Integer to digit conversion }
  val := 123;
  { Extract digits }
  vc := val mod 10;        { 3 }
  vb := (val div 10) mod 10; { 2 }
  va := val div 100;        { 1 }
  if (va = 1) and (vb = 2) and (vc = 3) then
    writeln('PASS 4')
  else
    writeln('FAIL 4');

  { Test 5: Simple loop simulating line search }
  pos := 0;
  val := 0;  { target line number }
  running := true;
  { Pretend lines 10,20,30 stored in t0-t2 }
  t0 := 10; t1 := 20; t2 := 30;
  while running do
  begin
    tok := 0;
    if pos = 0 then tok := t0;
    if pos = 1 then tok := t1;
    if pos = 2 then tok := t2;
    if tok = 20 then
    begin
      val := pos;
      running := false
    end;
    pos := pos + 1;
    if pos >= 3 then
      running := false
  end;
  if val = 1 then
    writeln('PASS 5')
  else
    writeln('FAIL 5');

  writeln('DONE')
end.

