var
  pass_count, fail_count: integer;

procedure check(ok: boolean; tag: integer);
begin
  if ok then
  begin
    write('PASS ');
    pass_count := pass_count + 1
  end
  else
  begin
    write('FAIL ');
    fail_count := fail_count + 1
  end;
  writeln(tag)
end;

begin
  init_keywords;
  pass_count := 0;
  fail_count := 0;

  { Test 1: Token value ranges }
  check(TOK_LET = 128, 1);
  check(TOK_ABS = 151, 2);
  check(TOK_PLUS = 160, 3);
  check(TOK_GE = 169, 4);
  check(TOK_LPAREN = 176, 5);
  check(TOK_VAR_A = 192, 6);
  check(TOK_INT = 224, 7);
  check(TOK_EOL = 0, 8);

  { Test 2: Keyword lengths }
  check(kw_len(0) = 3, 9);     { LET }
  check(kw_len(1) = 5, 10);    { PRINT }
  check(kw_len(3) = 2, 11);    { IF }
  check(kw_len(7) = 6, 12);    { RETURN }
  check(kw_len(9) = 2, 13);    { TO }

  { Test 3: Keyword characters }
  check(kw_char(0, 0) = 'L', 14);
  check(kw_char(0, 1) = 'E', 15);
  check(kw_char(0, 2) = 'T', 16);
  check(kw_char(1, 0) = 'P', 17);   { PRINT }
