  { Variable tokens (0xC0-0xD9) }
  TOK_VAR_A  = 192;
  TOK_VAR_Z  = 217;

  { Literal tokens }
  TOK_INT    = 224;
  TOK_STR    = 225;

  { End of line }
  TOK_EOL    = 0;

  { Keyword table: flat array, 8 chars per entry }
  KW_WIDTH = 8;

var
  kw_table: array[0..191] of char;
  test_fail: integer;

{ --- Keyword table management --- }

procedure kw_set(idx: integer; s0, s1, s2, s3, s4, s5, s6, s7: char);
var base: integer;
begin
  base := idx * KW_WIDTH;
  kw_table[base]     := s0;
  kw_table[base + 1] := s1;
  kw_table[base + 2] := s2;
  kw_table[base + 3] := s3;
