    Literals:   0xE0 (int), 0xE1 (string)
    EOL:        0x00

  NOTE: p24p limits — MAX_SYMBOLS=64, MAX_STRINGS=16, MAX_PROCS=32.
  Keep named constants minimal; use inline literals where safe. }

const
  { Only the constants frequently used in code are named.
    Full token byte values documented in comments above. }
  FIRST_KEYWORD = 128;
  LAST_KEYWORD  = 151;
  TOK_PLUS  = 160;   { first operator }
  TOK_GE    = 169;   { last operator }
  TOK_VAR_A = 192;   { first variable }
  TOK_VAR_Z = 217;   { last variable }
  TOK_INT   = 224;   { integer literal prefix }
  TOK_STR   = 225;   { string literal prefix }
  KW_WIDTH  = 8;     { chars per keyword entry }
  NUM_KW    = 24;    { total keywords }

var
  kw_table: array[0..191] of char;

{ --- Keyword table --- }

procedure kw_set(idx: integer; s0, s1, s2, s3, s4, s5, s6, s7: char);
var base: integer;
begin
  base := idx * KW_WIDTH;
  kw_table[base]     := s0;
  kw_table[base + 1] := s1;
  kw_table[base + 2] := s2;
  kw_table[base + 3] := s3;
  kw_table[base + 4] := s4;
  kw_table[base + 5] := s5;
  kw_table[base + 6] := s6;
  kw_table[base + 7] := s7
end;

procedure init_keywords;
begin
  kw_set( 0, 'L','E','T',' ',' ',' ',' ',' ');
  kw_set( 1, 'P','R','I','N','T',' ',' ',' ');
  kw_set( 2, 'I','N','P','U','T',' ',' ',' ');
  kw_set( 3, 'I','F',' ',' ',' ',' ',' ',' ');
  kw_set( 4, 'T','H','E','N',' ',' ',' ',' ');
  kw_set( 5, 'G','O','T','O',' ',' ',' ',' ');
  kw_set( 6, 'G','O','S','U','B',' ',' ',' ');
  kw_set( 7, 'R','E','T','U','R','N',' ',' ');
  kw_set( 8, 'F','O','R',' ',' ',' ',' ',' ');
  kw_set( 9, 'T','O',' ',' ',' ',' ',' ',' ');
  kw_set(10, 'S','T','E','P',' ',' ',' ',' ');
  kw_set(11, 'N','E','X','T',' ',' ',' ',' ');
  kw_set(12, 'S','T','O','P',' ',' ',' ',' ');
  kw_set(13, 'E','N','D',' ',' ',' ',' ',' ');
  kw_set(14, 'R','E','M',' ',' ',' ',' ',' ');
  kw_set(15, 'L','I','S','T',' ',' ',' ',' ');
  kw_set(16, 'R','U','N',' ',' ',' ',' ',' ');
  kw_set(17, 'N','E','W',' ',' ',' ',' ',' ');
  kw_set(18, 'S','A','V','E',' ',' ',' ',' ');
  kw_set(19, 'L','O','A','D',' ',' ',' ',' ');
  kw_set(20, 'B','Y','E',' ',' ',' ',' ',' ');
  kw_set(21, 'P','E','E','K',' ',' ',' ',' ');
  kw_set(22, 'P','O','K','E',' ',' ',' ',' ');
  kw_set(23, 'A','B','S',' ',' ',' ',' ',' ')
end;

function kw_len(idx: integer): integer;
var base, len: integer;
begin
  base := idx * KW_WIDTH;
  len := KW_WIDTH;
  while (len > 0) and (kw_table[base + len - 1] = ' ') do
    len := len - 1;
  kw_len := len
end;

function kw_char(idx, pos: integer): char;
begin
  kw_char := kw_table[idx * KW_WIDTH + pos]
end;

{ --- Token classification --- }

function is_keyword(tok: integer): boolean;
begin
  is_keyword := (tok >= FIRST_KEYWORD) and (tok <= LAST_KEYWORD)
end;

function is_operator(tok: integer): boolean;
begin
  is_operator := (tok >= TOK_PLUS) and (tok <= TOK_GE)
end;

function is_variable(tok: integer): boolean;
begin
  is_variable := (tok >= TOK_VAR_A) and (tok <= TOK_VAR_Z)
end;

function var_index(tok: integer): integer;
begin
  var_index := tok - TOK_VAR_A
end;

function var_token(idx: integer): integer;
begin
  var_token := idx + TOK_VAR_A
end;

