begin
  if tok = TOK_PLUS    then write('+');
  if tok = TOK_PLUS+1  then write('-');
  if tok = TOK_PLUS+2  then write('*');
  if tok = TOK_PLUS+3  then write('/');
  if tok = TOK_PLUS+4  then write('=');
  if tok = TOK_PLUS+5  then begin write('<'); write('>') end;
  if tok = TOK_PLUS+6  then write('<');
  if tok = TOK_PLUS+7  then begin write('<'); write('=') end;
  if tok = TOK_PLUS+8  then write('>');
  if tok = TOK_GE      then begin write('>'); write('=') end
end;

procedure print_variable(tok: integer);
var ch: char;
begin
  ch := chr(ord('A') + tok - TOK_VAR_A);
  write(ch)
end;

{ --- Self-test --- }

procedure check(ok: boolean; id: integer);
begin
  if ok then write('P') else write('F');
  writeln(id)
end;

begin
  init_keywords;

  { Keyword table }
  check(kw_len(0) = 3, 1);
  check(kw_len(1) = 5, 2);
  check(kw_len(3) = 2, 3);
  check(kw_len(7) = 6, 4);
  check(kw_len(9) = 2, 5);
  check(kw_char(0, 0) = 'L', 6);
  check(kw_char(0, 2) = 'T', 7);
  check(kw_char(1, 0) = 'P', 8);
  check(kw_char(5, 0) = 'G', 9);

  { Classification }
  check(is_keyword(128), 10);
  check(is_keyword(151), 11);
  check(not is_keyword(160), 12);
  check(is_operator(160), 13);
  check(is_operator(169), 14);
  check(not is_operator(128), 15);
  check(is_variable(192), 16);
  check(is_variable(217), 17);
  check(not is_variable(128), 18);

  { Variable indexing }
  check(var_index(192) = 0, 19);
  check(var_index(217) = 25, 20);
  check(var_token(0) = 192, 21);
  check(var_token(25) = 217, 22);

  { Detokenizer visual output }
  print_keyword(129);
  writeln(0);
  print_operator(167);
  writeln(0);
  print_variable(192);
  writeln(0);

  writeln(99)
end.

