  if tok = TOK_LT    then write('<');
  if tok = TOK_LE    then begin write('<'); write('=') end;
  if tok = TOK_GT    then write('>');
  if tok = TOK_GE    then begin write('>'); write('=') end
end;

procedure print_variable(tok: integer);
var ch: char;
begin
  ch := chr(ord('A') + tok - TOK_VAR_A);
  write(ch)
end;

{ --- Self-test: uses integer IDs to avoid string literal limit --- }

procedure check(ok: boolean; id: integer);
begin
  if ok then
    write('P')
  else
  begin
    write('F');
    test_fail := test_fail + 1
  end;
  writeln(id)
end;

begin
  init_keywords;
  test_fail := 0;

  { Keyword lengths }
  check(kw_len(0) = 3, 1);
  check(kw_len(1) = 5, 2);
  check(kw_len(3) = 2, 3);
  check(kw_len(7) = 6, 4);
  check(kw_len(9) = 2, 5);

  { Keyword chars }
  check(kw_char(0, 0) = 'L', 6);
  check(kw_char(0, 2) = 'T', 7);
  check(kw_char(1, 0) = 'P', 8);
  check(kw_char(5, 0) = 'G', 9);

  { Classification }
  check(is_keyword(TOK_LET), 10);
  check(is_keyword(TOK_ABS), 11);
  check(not is_keyword(TOK_PLUS), 12);
  check(is_operator(TOK_PLUS), 13);
  check(is_operator(TOK_GE), 14);
  check(not is_operator(TOK_LET), 15);
  check(is_variable(TOK_VAR_A), 16);
  check(is_variable(TOK_VAR_Z), 17);
  check(not is_variable(TOK_LET), 18);

  { Variable indexing }
  check(var_index(TOK_VAR_A) = 0, 19);
  check(var_index(TOK_VAR_Z) = 25, 20);
  check(var_token(0) = TOK_VAR_A, 21);
  check(var_token(25) = TOK_VAR_Z, 22);

  { Detokenizer visual: PRINT }
  print_keyword(TOK_PRINT);
  writeln(0);
  { Detokenizer visual: <= }
  print_operator(TOK_LE);
  writeln(0);
  { Detokenizer visual: A }
  print_variable(TOK_VAR_A);
  writeln(0);

  writeln(test_fail)
end.

