program BasicLex;
{ COR24 BASIC v1 — Tokenizer. Converts BASIC text to token bytes. }
const
  FIRST_KEYWORD = 128;
  LAST_KEYWORD  = 151;
  TOK_PLUS  = 160;
  TOK_GE    = 169;
  TOK_VAR_A = 192;
  TOK_VAR_Z = 217;
  TOK_INT   = 224;
  TOK_STR   = 225;
  KW_WIDTH  = 8;
  NUM_KW    = 24;
  MAX_TOK   = 128;
var
  kw_table: array[0..191] of char;
  line_buf: array[0..79] of char;
  line_len, line_pos: integer;
  tok_buf: array[0..127] of integer;
  tok_len, tok_line_num: integer;

procedure kw_set(idx: integer; s0,s1,s2,s3,s4,s5,s6,s7: char);
var b: integer;
begin
  b := idx * KW_WIDTH;
  kw_table[b]:=s0; kw_table[b+1]:=s1; kw_table[b+2]:=s2; kw_table[b+3]:=s3;
  kw_table[b+4]:=s4; kw_table[b+5]:=s5; kw_table[b+6]:=s6; kw_table[b+7]:=s7
end;

procedure init_keywords;
begin
  kw_set( 0,'L','E','T',' ',' ',' ',' ',' ');
  kw_set( 1,'P','R','I','N','T',' ',' ',' ');
  kw_set( 2,'I','N','P','U','T',' ',' ',' ');
  kw_set( 3,'I','F',' ',' ',' ',' ',' ',' ');
  kw_set( 4,'T','H','E','N',' ',' ',' ',' ');
  kw_set( 5,'G','O','T','O',' ',' ',' ',' ');
  kw_set( 6,'G','O','S','U','B',' ',' ',' ');
  kw_set( 7,'R','E','T','U','R','N',' ',' ');
  kw_set( 8,'F','O','R',' ',' ',' ',' ',' ');
  kw_set( 9,'T','O',' ',' ',' ',' ',' ',' ');
  kw_set(10,'S','T','E','P',' ',' ',' ',' ');
  kw_set(11,'N','E','X','T',' ',' ',' ',' ');
  kw_set(12,'S','T','O','P',' ',' ',' ',' ');
  kw_set(13,'E','N','D',' ',' ',' ',' ',' ');
  kw_set(14,'R','E','M',' ',' ',' ',' ',' ');
  kw_set(15,'L','I','S','T',' ',' ',' ',' ');
  kw_set(16,'R','U','N',' ',' ',' ',' ',' ');
  kw_set(17,'N','E','W',' ',' ',' ',' ',' ');
  kw_set(18,'S','A','V','E',' ',' ',' ',' ');
  kw_set(19,'L','O','A','D',' ',' ',' ',' ');
  kw_set(20,'B','Y','E',' ',' ',' ',' ',' ');
  kw_set(21,'P','E','E','K',' ',' ',' ',' ');
  kw_set(22,'P','O','K','E',' ',' ',' ',' ');
  kw_set(23,'A','B','S',' ',' ',' ',' ',' ')
end;

function kw_len(idx: integer): integer;
var b,l: integer;
begin
  b := idx * KW_WIDTH; l := KW_WIDTH;
  while (l > 0) and (kw_table[b+l-1] = ' ') do l := l-1;
  kw_len := l
end;

function upcase(ch: char): char;
begin
  if (ch >= 'a') and (ch <= 'z') then upcase := chr(ord(ch)-32)
  else upcase := ch
end;

function is_digit(ch: char): boolean;
begin is_digit := (ch >= '0') and (ch <= '9') end;

function is_letter(ch: char): boolean;
var u: char;
begin u := upcase(ch); is_letter := (u >= 'A') and (u <= 'Z') end;

procedure emit(v: integer);
begin
